import{_ as s,j as a,p as o,at as n}from"./chunks/framework.CFWbLlrS.js";const p=JSON.parse('{"title":"Session","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/sdk/session.md","filePath":"en-US/sdk/session.md"}'),i={name:"en-US/sdk/session.md"};function t(r,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to “Session”">​</a></h1><p><strong>Session</strong> is a wrapper around events, containing all event information along with the Bot instance that triggered the event. Event listener callbacks receive a Session instance as their argument.</p><h2 id="constructor" tabindex="-1">Constructor <a class="header-anchor" href="#constructor" aria-label="Permalink to “Constructor”">​</a></h2><h3 id="new-session" tabindex="-1">new Session(bot, event) <a class="header-anchor" href="#new-session" aria-label="Permalink to “new Session(bot, event)”">​</a></h3><ul><li><strong>bot:</strong> <a href="./bot.html"><code>Bot</code></a> bot instance</li><li><strong>event:</strong> <code>Partial&lt;Event&gt;</code> event data</li></ul><p>Create a new session instance. <code>selfId</code>, <code>platform</code>, and <code>timestamp</code> are automatically populated from the Bot.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You usually don&#39;t need to construct a Session manually. Use <a href="./bot.html#bot-session-event"><code>bot.session()</code></a> instead.</p></div><h2 id="instance-properties" tabindex="-1">Instance Properties <a class="header-anchor" href="#instance-properties" aria-label="Permalink to “Instance Properties”">​</a></h2><h3 id="session-sn" tabindex="-1">session.sn <a class="header-anchor" href="#session-sn" aria-label="Permalink to “session.sn”">​</a></h3><ul><li>Type: <code>number</code></li></ul><p>The session sequence number, unique within the current context.</p><h3 id="session-bot" tabindex="-1">session.bot <a class="header-anchor" href="#session-bot" aria-label="Permalink to “session.bot”">​</a></h3><ul><li>Type: <a href="./bot.html"><code>Bot</code></a></li></ul><p>The Bot instance that triggered the event.</p><h3 id="session-event" tabindex="-1">session.event <a class="header-anchor" href="#session-event" aria-label="Permalink to “session.event”">​</a></h3><ul><li>Type: <code>Event</code></li></ul><p>The original event object containing all event information.</p><h3 id="session-locales" tabindex="-1">session.locales <a class="header-anchor" href="#session-locales" aria-label="Permalink to “session.locales”">​</a></h3><ul><li>Type: <code>string[]</code></li></ul><p>The language preference list for the current session.</p><h2 id="event-accessors" tabindex="-1">Event Accessors <a class="header-anchor" href="#event-accessors" aria-label="Permalink to “Event Accessors”">​</a></h2><p>The following properties provide shortcut access to fields in <code>session.event</code>. They are readable and writable.</p><h3 id="session-type" tabindex="-1">session.type <a class="header-anchor" href="#session-type" aria-label="Permalink to “session.type”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The event type, derived from <code>event.type</code>.</p><h3 id="session-selfid" tabindex="-1">session.selfId <a class="header-anchor" href="#session-selfid" aria-label="Permalink to “session.selfId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The bot&#39;s platform account ID, derived from <code>event.selfId</code>.</p><h3 id="session-platform" tabindex="-1">session.platform <a class="header-anchor" href="#session-platform" aria-label="Permalink to “session.platform”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The platform name of the event, derived from <code>event.platform</code>.</p><h3 id="session-timestamp" tabindex="-1">session.timestamp <a class="header-anchor" href="#session-timestamp" aria-label="Permalink to “session.timestamp”">​</a></h3><ul><li>Type: <code>number</code></li></ul><p>The event timestamp, derived from <code>event.timestamp</code>.</p><h3 id="session-userid" tabindex="-1">session.userId <a class="header-anchor" href="#session-userid" aria-label="Permalink to “session.userId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The ID of the user who triggered the event, derived from <code>event.user.id</code>.</p><h3 id="session-channelid" tabindex="-1">session.channelId <a class="header-anchor" href="#session-channelid" aria-label="Permalink to “session.channelId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The channel ID of the event, derived from <code>event.channel.id</code>.</p><h3 id="session-channelname" tabindex="-1">session.channelName <a class="header-anchor" href="#session-channelname" aria-label="Permalink to “session.channelName”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The channel name of the event, derived from <code>event.channel.name</code>.</p><h3 id="session-guildid" tabindex="-1">session.guildId <a class="header-anchor" href="#session-guildid" aria-label="Permalink to “session.guildId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The guild ID of the event, derived from <code>event.guild.id</code>.</p><h3 id="session-guildname" tabindex="-1">session.guildName <a class="header-anchor" href="#session-guildname" aria-label="Permalink to “session.guildName”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The guild name of the event, derived from <code>event.guild.name</code>.</p><h3 id="session-messageid" tabindex="-1">session.messageId <a class="header-anchor" href="#session-messageid" aria-label="Permalink to “session.messageId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The message ID associated with the event, derived from <code>event.message.id</code>.</p><h3 id="session-operatorid" tabindex="-1">session.operatorId <a class="header-anchor" href="#session-operatorid" aria-label="Permalink to “session.operatorId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The operator ID of the event, derived from <code>event.operator.id</code>.</p><h3 id="session-roleid" tabindex="-1">session.roleId <a class="header-anchor" href="#session-roleid" aria-label="Permalink to “session.roleId”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The role ID associated with the event, derived from <code>event.role.id</code>.</p><h3 id="session-quote" tabindex="-1">session.quote <a class="header-anchor" href="#session-quote" aria-label="Permalink to “session.quote”">​</a></h3><ul><li>Type: <a href="./../resources/message.html#def-message"><code>Message</code></a></li></ul><p>The quoted message, derived from <code>event.message.quote</code>.</p><h3 id="session-referrer" tabindex="-1">session.referrer <a class="header-anchor" href="#session-referrer" aria-label="Permalink to “session.referrer”">​</a></h3><ul><li>Type: <code>any</code></li></ul><p>Platform context information for passive request scenarios. Derived from <code>event.referrer</code>.</p><h2 id="computed-properties" tabindex="-1">Computed Properties <a class="header-anchor" href="#computed-properties" aria-label="Permalink to “Computed Properties”">​</a></h2><h3 id="session-isdirect" tabindex="-1">session.isDirect <a class="header-anchor" href="#session-isdirect" aria-label="Permalink to “session.isDirect”">​</a></h3><ul><li>Type: <code>boolean</code></li></ul><p>Whether the current session is a direct message. Returns <code>true</code> when <code>event.channel.type</code> is <code>DIRECT</code>.</p><h3 id="session-content" tabindex="-1">session.content <a class="header-anchor" href="#session-content" aria-label="Permalink to “session.content”">​</a></h3><ul><li>Type: <code>string</code></li></ul><p>The string representation of the message content. Reading serializes <code>event.message.elements</code> to a string; setting parses the string into message elements and automatically extracts the <code>quote</code> element.</p><h3 id="session-elements" tabindex="-1">session.elements <a class="header-anchor" href="#session-elements" aria-label="Permalink to “session.elements”">​</a></h3><ul><li>Type: <code>Element[]</code></li></ul><p>The message element array, derived from <code>event.message.elements</code>.</p><h3 id="session-author" tabindex="-1">session.author <a class="header-anchor" href="#session-author" aria-label="Permalink to “session.author”">​</a></h3><h2 id="instance-methods" tabindex="-1">Instance Methods <a class="header-anchor" href="#instance-methods" aria-label="Permalink to “Instance Methods”">​</a></h2><h3 id="session-setinternal" tabindex="-1">session.setInternal(type, data) <a class="header-anchor" href="#session-setinternal" aria-label="Permalink to “session.setInternal(type, data)”">​</a></h3><ul><li><strong>type:</strong> <code>string</code> internal event type</li><li><strong>data:</strong> <code>any</code> internal event data</li></ul><p>Set internal event information. Writes <code>_type</code> and <code>_data</code> to the event object and mounts <code>data</code> onto <code>session[type]</code>.</p><h3 id="session-transform" tabindex="-1">session.transform(elements) <a class="header-anchor" href="#session-transform" aria-label="Permalink to “session.transform(elements)”">​</a></h3><ul><li><strong>elements:</strong> <code>Element[]</code> message elements</li><li>Returns: <code>Promise&lt;Element[]&gt;</code></li></ul><p>Transform message elements through the component system. Recursively replaces custom components with their rendered results.</p>',82)])])}const u=s(i,[["render",t]]);export{p as __pageData,u as default};
